func newSyncCmd(flags *rootFlags) *cobra.Command {
	var flagEvent string
	var flagDB string

	cmd := &cobra.Command{
		Use:     "sync",
		Short:   "Re-fetch watched events' current price + append to local price history",
		Example: "  ticketdata-pp-cli sync\n  ticketdata-pp-cli sync --event 22323960 --agent",
		RunE: func(cmd *cobra.Command, args []string) error {
			eventID := strings.TrimSpace(flagEvent)
			dbPath := flagDB
			if dbPath == "" {
				dbPath = defaultDBPath("ticketdata-pp-cli")
			}
			if dryRunOK(flags) {
				n := 1
				if eventID == "" {
					n = bestEffortWatchCount(cmd.Context(), dbPath)
				}
				fmt.Fprintf(cmd.OutOrStdout(), "would sync %d watched events\n", n)
				return nil
			}

			db, err := store.OpenWithContext(cmd.Context(), dbPath)
			if err != nil {
				return fmt.Errorf("opening store: %w", err)
			}
			defer db.Close()
			if err := db.EnsureTicketdataTables(cmd.Context()); err != nil {
				return err
			}

			ids := make([]string, 0)
			if eventID != "" {
				ids = append(ids, eventID)
			} else {
				watches, err := db.ListWatch(cmd.Context())
				if err != nil {
					return err
				}
				for _, w := range watches {
					id := strings.TrimSpace(w.EventID)
					if id != "" {
						ids = append(ids, id)
					}
				}
			}
			if len(ids) == 0 {
				if flags.asJSON || !isTerminal(cmd.OutOrStdout()) {
					empty := map[string]any{"status": "empty", "count": 0, "ok": 0, "failed": 0, "results": make([]syncResult, 0), "message": "watchlist is empty; add events with `ticketdata-pp-cli watch add <event-id>`"}
					return printJSONFiltered(cmd.OutOrStdout(), empty, flags)
				}
				fmt.Fprintln(cmd.OutOrStdout(), "watchlist is empty; add events with `ticketdata-pp-cli watch add <event-id>`")
				return nil
			}
			if cliutil.IsDogfoodEnv() && len(ids) > 3 {
				ids = ids[:3]
			}

			c, err := flags.newClient()
			if err != nil {
				return err
			}

			results := make([]syncResult, 0, len(ids))
			okCount := 0
			for _, id := range ids {
				result, err := syncOneEvent(cmd.Context(), c, db, id)
				if err != nil {
					if result.EventID == "" {
						result.EventID = id
					}
					result.OK = false
					result.Error = err.Error()
				}
				if result.OK {
					okCount++
				}
				results = append(results, result)
			}
			if okCount > 0 {
				if err := db.SaveSyncState("events", "", okCount); err != nil {
					return fmt.Errorf("saving sync state: %w", err)
				}
			}

			out := syncEnvelope{
				Status:  "complete",
				Count:   len(results),
				OK:      okCount,
				Failed:  len(results) - okCount,
				Results: results,
			}
			if flags.asJSON || (!isTerminal(cmd.OutOrStdout()) && !flags.csv && !flags.quiet && !flags.plain) {
				return printJSONFiltered(cmd.OutOrStdout(), out, flags)
			}
			return printSyncSummary(cmd, out)
		},
	}
	cmd.Flags().StringVar(&flagEvent, "event", "", "Sync only this event id instead of the whole watchlist")
	cmd.Flags().StringVar(&flagDB, "db", "", "SQLite database file path (default: resolved data directory data.db)")
	return cmd
}

func isNumericEventID(id string) bool {
	if id == "" {
		return false
	}
	for _, r := range id {
		if r < '0' || r > '9' {
			return false
		}
	}
	return true
}

func syncOneEvent(ctx context.Context, c *client.Client, db *store.Store, id string) (syncResult, error) {
	result := syncResult{EventID: id}
	if !isNumericEventID(id) {
		result.OK = false
		result.Error = "invalid event id (must be numeric, e.g. 22323960)"
		return result, nil
	}
	if err := db.EnsureTicketdataTables(ctx); err != nil {
		return result, err
	}

	raw, err := c.Get(ctx, "/events/"+id, nil)
	if err != nil {
		return result, err
	}
	var env struct {
		Status string          `json:"status"`
		Data   json.RawMessage `json:"data"`
	}
	if err := json.Unmarshal(raw, &env); err != nil {
		return result, fmt.Errorf("parse event envelope: %w", err)
	}
	var event ticketdataEventData
	if len(env.Data) > 0 && string(env.Data) != "null" {
		if err := json.Unmarshal(env.Data, &event); err != nil {
			return result, fmt.Errorf("parse event data: %w", err)
		}
	}
	if event.Found != nil && !*event.Found {
		result.OK = false
		result.Error = "event not found"
		return result, nil
	}

	eventID := strings.TrimSpace(event.Event.ID.String())
	if eventID == "" {
		eventID = id
	}
	result.EventID = eventID
	result.Title = event.Event.Title
	result.PerformerName = event.Performer.Name
	result.PerformerSlug = event.Performer.Slug
	result.VenueName = event.Venue.Name
	result.VenueSlug = event.Venue.Slug
	result.GetInPrice = event.Tickets.GetInPrice

	watchMeta := store.TDWatch{
		EventID:       eventID,
		Title:         event.Event.Title,
		PerformerName: event.Performer.Name,
		PerformerSlug: event.Performer.Slug,
		VenueName:     event.Venue.Name,
		VenueSlug:     event.Venue.Slug,
	}
	if err := db.UpdateWatchMeta(ctx, watchMeta); err != nil {
		return result, err
	}

	now := time.Now().UTC().Format(time.RFC3339)
	if err := db.InsertSnapshot(ctx, store.TDSnapshot{
		EventID:             eventID,
		GetInPrice:          event.Tickets.GetInPrice,
		MaxPrice:            event.Tickets.MaxPrice,
		NumberOfListings:    int(event.Tickets.NumberOfListings),
		ForecastValue:       event.ForecastValue,
		ForecastAvailable:   event.ForecastIsAvailable,
		ThreeDayChangePct:   event.ThreeDayPriceChange.Percent,
		PriceTrendDirection: event.PriceTrend.Direction,
		CapturedAt:          now,
	}); err != nil {
		return result, err
	}

	if err := upsertSearchResources(db, eventID, event); err != nil {
		return result, err
	}

	historyRaw, err := c.Get(ctx, "/events/"+id+"/price-history", nil)
	if err != nil {
		return result, err
	}
	var historyEnv struct {
		Status string          `json:"status"`
		Data   json.RawMessage `json:"data"`
	}
	if err := json.Unmarshal(historyRaw, &historyEnv); err != nil {
		return result, fmt.Errorf("parse price history envelope: %w", err)
	}
	var history ticketdataHistoryData
	if len(historyEnv.Data) > 0 && string(historyEnv.Data) != "null" {
		if err := json.Unmarshal(historyEnv.Data, &history); err != nil {
			return result, fmt.Errorf("parse price history data: %w", err)
		}
	}

	pricePoints := make([]store.TDPricePoint, 0, len(history.Data))
	for _, pt := range history.Data {
		pricePoints = append(pricePoints, store.TDPricePoint{
			GetInPrice: pt.GetInPrice,
			InsertedAt: pt.InsertedAt,
		})
	}
	zonePoints := make([]store.TDZonePoint, 0)
	for _, zone := range history.Zones {
		for _, pt := range zone.Data {
			zonePoints = append(zonePoints, store.TDZonePoint{
				Zone:       zone.Zone,
				GetInPrice: pt.GetInPrice,
				InsertedAt: pt.InsertedAt,
			})
		}
	}
	if cliutil.IsDogfoodEnv() {
		pricePoints = latestPricePoints(pricePoints, 200)
		zonePoints = latestZonePoints(zonePoints, 200)
	}

	beforePriceCount, err := countTDRows(ctx, db, `SELECT COUNT(*) FROM td_price_points WHERE event_id = ?`, eventID)
	if err != nil {
		return result, err
	}
	if err := db.UpsertPricePoints(ctx, eventID, pricePoints); err != nil {
		return result, err
	}
	afterPriceCount, err := countTDRows(ctx, db, `SELECT COUNT(*) FROM td_price_points WHERE event_id = ?`, eventID)
	if err != nil {
		return result, err
	}
	result.PricePointsAdded = afterPriceCount - beforePriceCount
	if result.PricePointsAdded < 0 {
		result.PricePointsAdded = 0
	}

	beforeZoneCount, err := countTDRows(ctx, db, `SELECT COUNT(*) FROM td_zone_points WHERE event_id = ?`, eventID)
	if err != nil {
		return result, err
	}
	if err := db.UpsertZonePoints(ctx, eventID, zonePoints); err != nil {
		return result, err
	}
	afterZoneCount, err := countTDRows(ctx, db, `SELECT COUNT(*) FROM td_zone_points WHERE event_id = ?`, eventID)
	if err != nil {
		return result, err
	}
	result.ZonePointsAdded = afterZoneCount - beforeZoneCount
	if result.ZonePointsAdded < 0 {
		result.ZonePointsAdded = 0
	}

	result.OK = true
	return result, nil
}

