func upsertSearchResources(db *store.Store, eventID string, event ticketdataEventData) error {
	eventDoc := map[string]any{
		"id":           eventID,
		"title":        event.Event.Title,
		"get_in_price": event.Tickets.GetInPrice,
		"performer": map[string]any{
			"name": event.Performer.Name,
			"slug": event.Performer.Slug,
		},
		"venue": map[string]any{
			"name": event.Venue.Name,
			"slug": event.Venue.Slug,
		},
	}
	eventJSON, err := json.Marshal(eventDoc)
	if err != nil {
		return fmt.Errorf("marshal event search document: %w", err)
	}
	if err := db.Upsert("events", eventID, eventJSON); err != nil {
		return fmt.Errorf("upsert event search document: %w", err)
	}

	if event.Performer.Slug != "" {
		performerJSON, err := json.Marshal(map[string]any{
			"slug": event.Performer.Slug,
			"name": event.Performer.Name,
		})
		if err != nil {
			return fmt.Errorf("marshal performer search document: %w", err)
		}
		if err := db.Upsert("performers", event.Performer.Slug, performerJSON); err != nil {
			return fmt.Errorf("upsert performer search document: %w", err)
		}
	}

	if event.Venue.Slug != "" {
		venueDoc := map[string]any{
			"slug": event.Venue.Slug,
			"name": event.Venue.Name,
		}
		if len(event.Venue.Location) > 0 && string(event.Venue.Location) != "null" {
			var location any
			if err := json.Unmarshal(event.Venue.Location, &location); err == nil {
				venueDoc["location"] = location
			}
		}
		venueJSON, err := json.Marshal(venueDoc)
		if err != nil {
			return fmt.Errorf("marshal venue search document: %w", err)
		}
		if err := db.Upsert("venues", event.Venue.Slug, venueJSON); err != nil {
			return fmt.Errorf("upsert venue search document: %w", err)
		}
	}
	return nil
}

func latestPricePoints(points []store.TDPricePoint, max int) []store.TDPricePoint {
	if max <= 0 || len(points) <= max {
		return points
	}
	capped := append([]store.TDPricePoint(nil), points...)
	sort.SliceStable(capped, func(i, j int) bool {
		return capped[i].InsertedAt < capped[j].InsertedAt
	})
	return capped[len(capped)-max:]
}

func latestZonePoints(points []store.TDZonePoint, max int) []store.TDZonePoint {
	if max <= 0 || len(points) <= max {
		return points
	}
	capped := append([]store.TDZonePoint(nil), points...)
	sort.SliceStable(capped, func(i, j int) bool {
		if capped[i].InsertedAt == capped[j].InsertedAt {
			return capped[i].Zone < capped[j].Zone
		}
		return capped[i].InsertedAt < capped[j].InsertedAt
	})
	return capped[len(capped)-max:]
}

func countTDRows(ctx context.Context, db *store.Store, query string, args ...any) (int, error) {
	var count int
	if err := db.DB().QueryRowContext(ctx, query, args...).Scan(&count); err != nil {
		return 0, fmt.Errorf("count ticketdata rows: %w", err)
	}
	return count, nil
}

func bestEffortWatchCount(ctx context.Context, dbPath string) int {
	db, err := store.OpenReadOnlyContext(ctx, dbPath)
	if err != nil {
		return 0
	}
	defer db.Close()

	var count int
	if err := db.DB().QueryRowContext(ctx, `SELECT COUNT(*) FROM td_watchlist`).Scan(&count); err != nil {
		return 0
	}
	return count
}

func printSyncSummary(cmd *cobra.Command, out syncEnvelope) error {
	fmt.Fprintf(cmd.OutOrStdout(), "synced %d/%d events\n", out.OK, out.Count)
	tw := newTabWriter(cmd.OutOrStdout())
	fmt.Fprintln(tw, "EVENT\tTITLE\tGET-IN\tPOINTS\tSTATUS")
	for _, result := range out.Results {
		status := "ok"
		if !result.OK {
			status = "error"
			if result.Error != "" {
				status = "error: " + result.Error
			}
		}
		fmt.Fprintf(tw, "%s\t%s\t%.2f\t%d\t%s\n",
			result.EventID,
			truncate(result.Title, 40),
			result.GetInPrice,
			result.PricePointsAdded,
			status,
		)
	}
	return tw.Flush()
}
